const item = $input.first().json;
const prompt = `Voce e um analista de prospeccao B2B. Analise a conta abaixo e gere JSON com: company_summary, likely_pains, approach_angle, linkedin_message, email_subject, email_body, follow_up, priority.

Empresa: ${item.company_name}
Site: ${item.website}
Segmento: ${item.segment}
Contato: ${item.contact_name} - ${item.contact_role}
Objetivo: ${item.goal}`;
return [{ json: { ...item, prompt } }];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || JSON.stringify(response);
return [{ json: { generated_prospecting_brief: content, created_at: new Date().toISOString() } }];
